/**
 * Minimal CSV parser (Papa Parse-compatible API subset).
 * Handles quoted fields, escaped quotes, newlines in quotes, and common edge cases.
 */
(function(global) {
  'use strict';

  var Papa = {};

  Papa.parse = function(input, config) {
    config = config || {};
    var delimiter = config.delimiter || ',';
    var header = config.header || false;
    var skipEmptyLines = config.skipEmptyLines || false;
    var transformHeader = config.transformHeader || null;
    var complete = config.complete || function() {};
    var error = config.error || function() {};

    function doWork(text) {
      try {
        var result = parseCSV(text, delimiter, header, skipEmptyLines, transformHeader);
        complete(result);
      } catch (e) {
        error(e);
      }
    }

    if (typeof input === 'string') {
      doWork(input);
    } else if (input instanceof File) {
      var reader = new FileReader();
      reader.onload = function() { doWork(reader.result); };
      reader.onerror = function() { error(new Error('Failed to read file')); };
      reader.readAsText(input);
    } else {
      error(new Error('Unsupported input type'));
    }
  };

  function parseCSV(text, delimiter, useHeader, skipEmpty, transformHeader) {
    var rows = [];
    var errors = [];
    var i = 0;
    var len = text.length;

    // Normalize line endings
    text = text.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
    len = text.length;

    while (i < len) {
      var row = [];
      while (i < len) {
        var field = '';
        // Skip leading whitespace before quotes (but preserve it otherwise)
        if (i < len && text[i] === '"') {
          // Quoted field
          i++; // skip opening quote
          while (i < len) {
            if (text[i] === '"') {
              if (i + 1 < len && text[i + 1] === '"') {
                field += '"';
                i += 2;
              } else {
                i++; // skip closing quote
                break;
              }
            } else {
              field += text[i];
              i++;
            }
          }
          // Skip to delimiter or newline
          while (i < len && text[i] !== delimiter && text[i] !== '\n') {
            i++;
          }
        } else {
          // Unquoted field
          while (i < len && text[i] !== delimiter && text[i] !== '\n') {
            field += text[i];
            i++;
          }
        }
        row.push(field);
        if (i < len && text[i] === delimiter) {
          i++; // skip delimiter
          // Handle trailing delimiter (empty last field)
          if (i >= len || text[i] === '\n') {
            row.push('');
          }
        } else {
          break;
        }
      }
      if (i < len && text[i] === '\n') {
        i++; // skip newline
      }
      // Skip empty lines
      if (skipEmpty && row.length === 1 && row[0].trim() === '') {
        continue;
      }
      rows.push(row);
    }

    if (rows.length === 0) {
      return { data: [], errors: [], meta: {} };
    }

    if (useHeader) {
      var headers = rows[0];
      if (transformHeader) {
        headers = headers.map(transformHeader);
      }
      var data = [];
      for (var r = 1; r < rows.length; r++) {
        // Skip empty lines in greedy mode
        if (skipEmpty === 'greedy') {
          var allEmpty = true;
          for (var c = 0; c < rows[r].length; c++) {
            if (rows[r][c].trim() !== '') { allEmpty = false; break; }
          }
          if (allEmpty) continue;
        }
        var obj = {};
        for (var c = 0; c < headers.length; c++) {
          obj[headers[c]] = c < rows[r].length ? rows[r][c] : '';
        }
        data.push(obj);
      }
      return { data: data, errors: errors, meta: { fields: headers } };
    }

    return { data: rows, errors: errors, meta: {} };
  }

  // Export
  if (typeof module !== 'undefined' && module.exports) {
    module.exports = Papa;
  } else {
    global.Papa = Papa;
  }
})(typeof window !== 'undefined' ? window : this);
